import React from 'react';
import { ChevronDown, ChevronRight, MoreVertical } from 'lucide-react';
import { MenuItem, SubMenu } from '../types';

interface SidebarProps {
  menus: MenuItem[];
  selectedSubMenuId: number | null;
  setSelectedSubMenuId: (id: number | null) => void;
  openMenus: Record<number, boolean>;
  toggleMenu: (id: number) => void;
  theme: 'light' | 'dark';
  isSidebarOpen: boolean;
  setIsSidebarOpen: (open: boolean) => void;
  favorites: string;
}

const Sidebar: React.FC<SidebarProps> = ({ 
  menus, 
  selectedSubMenuId, 
  setSelectedSubMenuId, 
  openMenus, 
  toggleMenu, 
  theme, 
  isSidebarOpen, 
  setIsSidebarOpen,
  favorites
}) => {
  return (
    <>
      <aside className={`
        absolute inset-y-0 left-0 z-40 w-64 border-r transform transition-transform duration-300 lg:relative lg:translate-x-0
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
        ${theme === 'dark' ? 'bg-slate-900 border-slate-800' : 'bg-slate-50 border-slate-200'}
      `}>
        <div className="p-4 flex flex-col h-full">
          <div className="flex items-center justify-between mb-6">
            <button className="flex items-center gap-2 px-4 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg text-sm font-medium w-full shadow-sm">
              <span>+ New</span>
              <ChevronDown size={14} className="ml-auto" />
            </button>
          </div>

          <nav className="flex-1 overflow-y-auto space-y-1">
            <div className="px-2 py-2 flex items-center justify-between text-xs font-bold uppercase tracking-wider opacity-50 mb-2">
              <div className="flex items-center gap-2">
                 <MoreVertical size={14} />
                 <span>{favorites}</span>
              </div>
              <span>30</span>
            </div>

            {menus.map(menu => (
              <div key={menu.id} className="space-y-1">
                <button 
                  onClick={() => toggleMenu(menu.id)}
                  className="w-full flex items-center gap-2 px-3 py-2 rounded-lg hover:bg-slate-200 dark:hover:bg-slate-800 transition-colors group"
                >
                  {openMenus[menu.id] ? <ChevronDown size={16} /> : <ChevronRight size={16} />}
                  <span className="flex-1 text-left font-medium text-sm">{menu.name}</span>
                  <span className="text-xs opacity-50">15</span>
                </button>
                
                {openMenus[menu.id] && (
                  <div className="ml-4 pl-4 border-l border-slate-200 dark:border-slate-700 space-y-1">
                    {menu.subMenus?.map(sub => (
                      <button
                        key={sub.id}
                        onClick={() => {
                          setSelectedSubMenuId(sub.id);
                          if(window.innerWidth < 1024) setIsSidebarOpen(false);
                        }}
                        className={`
                          w-full text-left px-3 py-1.5 rounded-md text-sm transition-all
                          ${selectedSubMenuId === sub.id 
                            ? 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400 font-semibold' 
                            : 'hover:bg-slate-200 dark:hover:bg-slate-800'}
                        `}
                      >
                        {sub.name}
                      </button>
                    ))}
                  </div>
                )}
              </div>
            ))}
          </nav>
        </div>
      </aside>

      {/* Backdrop for mobile */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/20 z-30 lg:hidden"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}
    </>
  );
};

export default Sidebar;
